// object
const user = { name: "Alice", age: 28 };
user.age += 1;
console.log(user);

class User:
    def __init__(self, name, age):
        self.name = name
        self.age = age
user = User("Alice", 28)

class User {
    String name;
    int age;
    User(String name, int age) {
        this.name = name;
        this.age = age;
    }
}
